  // =========================================================================
  // while_becomes_for
  // =========================================================================
  test("while_becomes_for") {
    assertCompresses(
      input = "while (foo()) bar()",
      expected = "for (; foo(); ) bar()",
      options = AllOff.copy(
        loops = true
      )
    )
  }

